import React, { useEffect, useState } from "react";

export default function UserProfile({ userId }) {
  const [profile, setProfile] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [ratings, setRatings] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!userId) return;
    setLoading(true);
    fetch(`http://localhost:8080/api/users/${userId}/profile`)
      .then(res => res.json())
      .then(data => {
        setProfile(data);
        if (data.role === "HUSTLER") {
          fetch(`http://localhost:8080/api/users/${userId}/hustler-completed-tasks`)
            .then(res => res.json())
            .then(setTasks);
          fetch(`http://localhost:8080/api/users/${userId}/hustler-ratings`)
            .then(res => res.json())
            .then(setRatings);
        } else if (data.role === "POSTER") {
          fetch(`http://localhost:8080/api/users/${userId}/poster-tasks`)
            .then(res => res.json())
            .then(setTasks);
        }
      })
      .finally(() => setLoading(false));
  }, [userId]);

  if (loading || !profile) return <div className="p-4">Loading profile...</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded shadow p-6 mt-6">
      <h2 className="text-2xl font-bold mb-2">{profile.username} <span className="text-sm text-gray-500">({profile.role})</span></h2>
      {profile.role === "HUSTLER" && ratings && (
        <div className="mb-4">
          <div className="font-semibold">Average Rating: <span className="text-yellow-500">{ratings.average.toFixed(2)}</span> / 5</div>
          <div className="mt-1 text-xs text-gray-500">({ratings.ratings.length} reviews)</div>
        </div>
      )}
      <div className="mb-4">
        <div className="font-semibold mb-1">
          {profile.role === "HUSTLER" ? "Completed Tasks" : "Posted Tasks"}
        </div>
        {tasks.length === 0 ? (
          <div className="text-gray-400">No tasks found.</div>
        ) : (
          <ul className="list-disc ml-5">
            {tasks.map(task => (
              <li key={task.id} className="mb-1">
                <span className="font-semibold">{task.title}</span>
                <span className="ml-2 text-xs text-gray-500">({task.status})</span>
              </li>
            ))}
          </ul>
        )}
      </div>
      {profile.role === "HUSTLER" && ratings && ratings.ratings.length > 0 && (
        <div className="mb-4">
          <div className="font-semibold mb-1">Ratings & Reviews</div>
          <ul className="border rounded divide-y">
            {ratings.ratings.map(r => (
              <li key={r.id} className="p-2">
                <div className="flex items-center gap-2">
                  <span className="text-yellow-500">{'★'.repeat(r.rating)}{'☆'.repeat(5 - r.rating)}</span>
                  <span className="text-xs text-gray-500">{new Date(r.createdAt).toLocaleDateString()}</span>
                </div>
                {r.comment && <div className="text-sm mt-1">{r.comment}</div>}
                <div className="text-xs text-gray-400 mt-1">From: {r.poster.username} on task: {r.task.title}</div>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
